#[derive(Default, Debug, Serialize)]
pub struct StationPlayerData {
    pub idle_crew: Crew,
    pub crew: Crew,
    pub trader: Option<CrewId>,
    pub cargo: ShipCargo,
    pub industry: BTreeMap<IndustryUnitId, IndustryUnit>,
}

impl StationPlayerData {
    pub fn new() -> StationPlayerData {
        StationPlayerData {
            cargo: ShipCargo::with_capacity(STATION_INIT_CARGO),
            ..Default::default()
        }
    }
}

pub struct Station {
    pub id: StationId,
    pub position: SpaceCoord,
    pub shipyard: RwLock<Vec<Ship>>,

    pub player_data: ShardedLockedData<PlayerId, Arc<RwLock<StationPlayerData>>>,
}

impl std::fmt::Debug for Station {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("Station")
            .field("id", &self.id)
            .field("position", &self.position)
            .finish_non_exhaustive()
    }
}

impl Station {
    pub fn init(id: u16, position: super::SpaceCoord) -> Station {
        Station {
            id,
            position,
            shipyard: RwLock::new(Ship::init_shipyard(position)),
            player_data: ShardedLockedData::new(100),
        }
    }

    pub async fn scan(&self, galaxy: &Galaxy) -> ScanResult {
        galaxy.scan_sector(1, &self.position).await
    }

    pub async fn cargo_price(&self, player: &PlayerId) -> f64 {
        let cap = if let Some(data) = self.player_data.clone_val(player).await {
            data.read().await.cargo.capacity
        } else {
            STATION_INIT_CARGO
        };
        CARGO_BASE_PRICE.powf((cap - STATION_INIT_CARGO) / CARGO_PRICE_INCDIV)
    }

    pub async fn buy_industry(
        &self,
        player: &mut Player,
        unit: IndustryUnitType,
    ) -> Result<(IndustryUnitId, f64), Errcode> {
        let cost = unit.get_price_buy();
        if player.money < cost {
            return Err(Errcode::NotEnoughMoney(player.money, cost));
        }
        self.ensure_has_player_data(&player.id).await;
        let pd = self.player_data.clone_val(&player.id).await.unwrap();
        let mut pd = pd.write().await;
        let unit = unit.new_unit();
        let unit_id = unit.id;
        pd.industry.insert(unit_id, unit);
        player.money -= cost;
        Ok((unit_id, cost))
    }

    pub async fn upgrade_industry(
        &self,
        player: &mut Player,
        id: &IndustryUnitId,
    ) -> Result<u8, Errcode> {
        self.ensure_has_player_data(&player.id).await;
        let pd = self.player_data.clone_val(&player.id).await.unwrap();
        let mut pd = pd.write().await;
        let Some(unit) = pd.industry.get_mut(id) else {
            return Err(Errcode::NoSuchIndustryUnit);
        };
        let cost = unit.price_next_rank();
        if cost > player.money {
            return Err(Errcode::NotEnoughMoney(player.money, cost));
        }
        player.money -= cost;
        unit.rank += 1;
        Ok(unit.rank)
    }

    pub async fn start_industry(
        &self,
        player: &PlayerId,
        id: &IndustryUnitId,
    ) -> Result<(), Errcode> {
        self.ensure_has_player_data(player).await;
        let pd = self.player_data.clone_val(player).await.unwrap();
        let mut pd = pd.write().await;
        let Some(unit) = pd.industry.get_mut(id) else {
            return Err(Errcode::NoSuchIndustryUnit);
        };
        unit.started = true;
        Ok(())
    }

    pub async fn stop_industry(
        &self,
        player: &PlayerId,
        id: &IndustryUnitId,
    ) -> Result<(), Errcode> {
        self.ensure_has_player_data(player).await;
        let pd = self.player_data.clone_val(player).await.unwrap();
        let mut pd = pd.write().await;
        let Some(unit) = pd.industry.get_mut(id) else {
            return Err(Errcode::NoSuchIndustryUnit);
        };
        unit.started = false;
        Ok(())
    }

    pub async fn buy_cargo(&self, player: &mut Player, amnt: &usize) -> Result<ShipCargo, Errcode> {
        let cost = (*amnt as f64) * self.cargo_price(&player.id).await;
        if cost > player.money {
            return Err(Errcode::NotEnoughMoney(player.money, cost));
        }
        player.money -= cost;
        self.ensure_has_player_data(&player.id).await;
        let pd = self.player_data.clone_val(&player.id).await.unwrap();
        let mut pd = pd.write().await;
        pd.cargo.capacity += *amnt as f64;
        Ok(pd.cargo.clone())
    }

    pub async fn add_cargo_cap(&self, player: &PlayerId, amnt: usize) -> ShipCargo {
        self.ensure_has_player_data(player).await;
        let pd = self.player_data.clone_val(player).await.unwrap();
        let mut pd = pd.write().await;
        pd.cargo.capacity += amnt as f64;
        pd.cargo.clone()
    }

    pub async fn assign_trader(&self, pid: &PlayerId, id: CrewId) -> Result<(), Errcode> {
        self.ensure_has_player_data(pid).await;
        let pd = self.player_data.clone_val(pid).await.unwrap();
        let mut pd = pd.write().await;
        let Some(cm) = pd.idle_crew.0.remove(&id) else {
            if pd.crew.0.contains_key(&id) {
                return Err(Errcode::CrewMemberNotIdle(id));
            } else {
                return Err(Errcode::CrewMemberNotFound(id));
            }
        };

        pd.crew.0.insert(id, cm);
        pd.trader = Some(id);
        Ok(())
    }

    pub async fn onboard_pilot(&self, ship: &mut Ship, id: &CrewId) -> Result<(), Errcode> {
        self.ensure_has_player_data(&ship.owner).await;
        let pd = self.player_data.clone_val(&ship.owner).await.unwrap();
        let mut pd = pd.write().await;
        let Some(cm) = pd.idle_crew.0.get(id) else {
            return Err(Errcode::CrewMemberNotIdle(*id));
        };
        if cm.member_type != CrewMemberType::Pilot {
            return Err(Errcode::WrongCrewType(CrewMemberType::Pilot));
        }
        ship.pilot = Some(*id);
        let pilot = pd.idle_crew.0.remove(id).unwrap();
        ship.crew.0.insert(*id, pilot);
        ship.update_perf_stats();
        Ok(())
    }

    pub async fn onboard_operator(
        &self,
        ship: &mut Ship,
        id: &CrewId,
        mod_id: &ShipModuleId,
    ) -> Result<(), Errcode> {
        self.ensure_has_player_data(&ship.owner).await;
        let cm = self
            .get_idle_crew(&ship.owner, id, CrewMemberType::Operator)
            .await?;
        let Some(module) = ship.modules.get_mut(mod_id) else {
            return Err(Errcode::NoSuchModule(*mod_id));
        };
        if !module.need(&cm.member_type) {
            return Err(Errcode::CrewNotNeeded);
        }
        module.operator = Some(*id);
        let pd = self.player_data.clone_val(&ship.owner).await.unwrap();
        let mut pd = pd.write().await;
        ship.crew.0.insert(*id, pd.idle_crew.0.remove(id).unwrap());
        Ok(())
    }

    pub async fn assign_crew_to_industry(
        &self,
        pid: &PlayerId,
        id: &CrewId,
        iid: &IndustryUnitId,
    ) -> Result<(), Errcode> {
        let cm = self
            .get_idle_crew(pid, id, CrewMemberType::Operator)
            .await?;
        let pd = self.player_data.clone_val(pid).await.unwrap();
        let mut pd = pd.write().await;
        let Some(industry) = pd.industry.get_mut(iid) else {
            return Err(Errcode::NoSuchIndustryUnit);
        };
        if !industry.need_crew_member(&cm.member_type) {
            return Err(Errcode::CrewNotNeeded);
        }
        industry.assign_operator(*id, &cm);
        let cm = pd.idle_crew.0.remove(id).unwrap();
        pd.crew.0.insert(*id, cm);
        Ok(())
    }

    pub async fn get_idle_crew(
        &self,
        pid: &PlayerId,
        id: &CrewId,
        ctype: CrewMemberType,
    ) -> Result<CrewMember, Errcode> {
        self.ensure_has_player_data(pid).await;
        let pd = self.player_data.clone_val(pid).await.unwrap();
        let pd = pd.read().await;
        let Some(cm) = pd.idle_crew.0.get(id) else {
            return Err(Errcode::CrewMemberNotIdle(*id));
        };
        if cm.member_type != ctype {
            return Err(Errcode::WrongCrewType(ctype));
        }
        Ok(cm.clone())
    }

    pub async fn buy_resource(
        &self,
        market: &Market,
        player: &PlayerId,
        resource: &Resource,
        amnt: f64,
    ) -> Result<MarketTx, Errcode> {
        self.ensure_has_player_data(player).await;
        let pd = self.player_data.clone_val(player).await.unwrap();
        let mut pd = pd.write().await;
        let Some(trader) = pd.trader else {
            return Err(Errcode::NoTraderAssigned);
        };
        let cm = pd.crew.0.get(&trader).unwrap();
        let can_cargo = pd.cargo.space_for(resource);
        let amnt = amnt.min(can_cargo);
        if amnt == 0.0 {
            return Err(Errcode::BuyNothing);
        }
        let tx = market.buy(cm, resource, amnt).await;
        let (r, a) = tx.added_cargo.unwrap();
        pd.cargo.add_resource(&r, a);
        Ok(tx)
    }

    pub async fn sell_resource(
        &self,
        market: &Market,
        player: &PlayerId,
        resource: &Resource,
        amnt: f64,
    ) -> Result<MarketTx, Errcode> {
        self.ensure_has_player_data(player).await;
        let pd = self.player_data.clone_val(player).await.unwrap();
        let mut pd = pd.write().await;
        let Some(trader) = pd.trader else {
            return Err(Errcode::NoTraderAssigned);
        };
        let cm = pd.crew.0.get(&trader).unwrap();
        let Some(can_cargo) = pd.cargo.resources.get(resource) else {
            return Err(Errcode::SellNothing);
        };
        let amnt = amnt.min(*can_cargo);
        if amnt <= 0.0 {
            return Err(Errcode::SellNothing);
        }
        let tx = market.sell(cm, resource, amnt).await;
        let (r, a) = tx.removed_cargo.unwrap();
        let unloaded = pd.cargo.unload(&r, a);
        debug_assert_eq!(unloaded, a);
        Ok(tx)
    }

    pub async fn refuel_ship(&self, ship: &mut Ship) -> Result<f64, Errcode> {
        if self.position != ship.position {
            return Err(Errcode::ShipNotInStation);
        }
        let Some(pd) = self.player_data.clone_val(&ship.owner).await else {
            return Err(Errcode::NoFuelInCargo);
        };
        let mut pd = pd.write().await;
        let Some(qty) = pd.cargo.resources.get(&Resource::Fuel) else {
            return Err(Errcode::NoFuelInCargo);
        };
        if *qty == 0.0 {
            return Err(Errcode::NoFuelInCargo);
        }
        debug_assert!(ship.fuel_tank >= 0.0);
        debug_assert!(ship.fuel_tank_capacity >= ship.fuel_tank);
        let needed = ship.fuel_tank_capacity - ship.fuel_tank;
        let unload = needed.min(*qty);
        let unloaded = pd.cargo.unload(&Resource::Fuel, unload);
        ship.fuel_tank += unloaded;
        debug_assert!(ship.fuel_tank_capacity >= ship.fuel_tank);
        Ok(unloaded)
    }

    pub async fn repair_ship(&self, ship: &mut Ship) -> Result<f64, Errcode> {
        if self.position != ship.position {
            return Err(Errcode::ShipNotInStation);
        }
        let Some(pd) = self.player_data.clone_val(&ship.owner).await else {
            return Err(Errcode::NoHullInCargo);
        };
        let mut pd = pd.write().await;
        let Some(qty) = pd.cargo.resources.get(&Resource::Hull) else {
            return Err(Errcode::NoHullInCargo);
        };
        if *qty == 0.0 {
            return Err(Errcode::NoHullInCargo);
        }
        debug_assert!(ship.hull_resistance >= ship.hull_decay);

        let amnt = ship.hull_decay.min(*qty);
        if amnt == 0.0 {
            return Ok(0.0);
        }
        let unloaded = pd.cargo.unload(&Resource::Hull, amnt);
        ship.hull_decay -= unloaded;
        debug_assert!(
            ship.hull_resistance >= ship.hull_decay,
            "{} < {}",
            ship.hull_resistance,
            ship.hull_decay
        );
        debug_assert!(ship.hull_decay >= 0.0, "{}", ship.hull_decay);
        debug_assert!(unloaded >= 0.0, "{}", unloaded);
        Ok(unloaded)
    }

    pub fn get_ship_upgrade_price(&self, _ship: &Ship, upgrade: &ShipUpgrade) -> f64 {
        upgrade.get_price()
    }

    pub async fn get_cargo_potential_price(&self, id: &PlayerId) -> f64 {
        let Some(pd) = self.player_data.clone_val(id).await else {
            return 0.0;
        };
        let pd = pd.read().await;
        pd.cargo
            .resources
            .iter()
            .map(|(r, amnt)| r.base_price() * amnt)
            .sum()
    }

    pub async fn add_resource(&self, id: &PlayerId, resource: &Resource, amnt: f64) -> f64 {
        self.ensure_has_player_data(id).await;
        let pd = self.player_data.clone_val(id).await.unwrap();
        let mut pd = pd.write().await;
        pd.cargo.add_resource(resource, amnt)
    }

    pub async fn buy_ship(&self, index: usize) -> Ship {
        // Ship starters, always keep them
        let mut ship = if index < 3 {
            let shipyard = self.shipyard.read().await;
            shipyard.get(index).unwrap().clone()
        } else {
            let mut shipyard = self.shipyard.write().await;
            let ship = shipyard.remove(index);
            shipyard.push(Ship::random(self.position));
            ship
        };
        ship.update_perf_stats();
        ship.fuel_tank = ship.fuel_tank_capacity;
        ship
    }

    pub async fn ensure_has_player_data(&self, id: &PlayerId) {
        if !self.player_data.contains_key(id).await {
            let pd = Arc::new(RwLock::new(StationPlayerData::new()));
            self.player_data.insert(*id, pd).await;
        }
    }

    pub async fn sum_all_wages(&self, id: &PlayerId) -> f64 {
        let Some(pd) = self.player_data.clone_val(id).await else {
            return 0.0;
        };
        let pd = pd.read().await;
        pd.crew.sum_wages() + pd.idle_crew.sum_wages()
    }

    pub async fn upgrade_station_crew(
        &self,
        id: &PlayerId,
        money: &mut f64,
        crew: &CrewId,
    ) -> Result<(f64, u8), Errcode> {
        let Some(pd) = self.player_data.clone_val(id).await else {
            return Err(Errcode::CrewMemberNotFound(*crew));
        };
        let mut pd = pd.write().await;

        let Some(cm) = pd.crew.0.get_mut(crew) else {
            return Err(Errcode::CrewMemberNotFound(*crew));
        };
        let price = cm.price_next_rank();
        if price > *money {
            return Err(Errcode::NotEnoughMoney(*money, price));
        }
        *money -= price;
        cm.rank += 1;
        Ok((price, cm.rank))
    }

    pub async fn hire_crew(&self, id: &PlayerId, crewtype: CrewMemberType) -> CrewId {
        let crewid = rand::rng().random();
        let member = CrewMember::from(crewtype);

        self.ensure_has_player_data(id).await;
        let pd = self.player_data.clone_val(id).await.unwrap();
        let mut pd = pd.write().await;
        pd.idle_crew.0.insert(crewid, member);
        crewid
    }

    pub async fn fire_crew(&self, id: &PlayerId, crewid: &CrewId) -> Result<CrewMember, Errcode> {
        self.ensure_has_player_data(id).await;
        let pd = self.player_data.clone_val(id).await.unwrap();
        let mut pd = pd.write().await;
        let Some(cm) = pd.idle_crew.0.remove(crewid) else {
            return Err(Errcode::CrewMemberNotFound(*crewid));
        };
        Ok(cm)
    }

    pub async fn upgr_trader_price(&self, id: &PlayerId) -> Option<f64> {
        let pd = self.player_data.clone_val(id).await?;
        let pd = pd.read().await;
        pd.trader.map(|trader| {
            let cm = pd.crew.0.get(&trader).unwrap();
            cm.price_next_rank()
        })
    }

    pub async fn clone_cargo(&self, id: &PlayerId) -> ShipCargo {
        let Some(pd) = self.player_data.clone_val(id).await else {
            return ShipCargo::with_capacity(STATION_INIT_CARGO);
        };
        let pd = pd.read().await;
        pd.cargo.clone()
    }

    pub async fn get_fee_rate(&self, id: &PlayerId) -> Result<f64, Errcode> {
        let Some(pd) = self.player_data.clone_val(id).await else {
            return Err(Errcode::NoTraderAssigned);
        };
        let pd = pd.read().await;
        let Some(trader) = pd.trader else {
            return Err(Errcode::NoTraderAssigned);
        };
        let cm = pd.crew.0.get(&trader).unwrap();
        Ok(fee_rate(cm.rank))
    }

    pub async fn to_json(&self, id: &PlayerId) -> serde_json::Value {
        if let Some(pd) = self.player_data.clone_val(id).await {
            let pd = pd.read().await;
            self._to_json(&pd)
        } else {
            let pd = StationPlayerData::new();
            self._to_json(&pd)
        }
    }

    fn _to_json(&self, data: &StationPlayerData) -> serde_json::Value {
        serde_json::json!({
            "id": self.id,
            "position": self.position,
            "crew": data.crew,
            "cargo": data.cargo,
            "idle_crew": data.idle_crew,
            "trader": data.trader,
        })
    }

    pub async fn update_crafting(&self, tdelta: f64, id: &PlayerId) {
        let Some(pd) = self.player_data.clone_val(id).await else {
            return;
        };
        let mut pd = pd.write().await;
        let all_industry = pd.industry.clone();
        for (_, industry) in all_industry.iter() {
            if let Some(ratio) = industry.can_work(&tdelta, &pd.cargo.resources) {
                let t = tdelta * ratio;
                industry.work(t, &mut pd.cargo.resources);
            }
        }
    }

    pub async fn get_industry_production(
        &self,
        pid: &PlayerId,
        id: IndustryUnitId,
    ) -> Result<(Vec<(Resource, f64)>, Vec<(Resource, f64)>), Errcode> {
        let Some(pd) = self.player_data.clone_val(pid).await else {
            return Err(Errcode::NoSuchIndustryUnit);
        };

        let pd = pd.read().await;
        let Some(industry) = pd.industry.get(&id) else {
            return Err(Errcode::NoSuchIndustryUnit);
        };

        let Some(opid) = industry.operator else {
            return Ok((vec![], vec![]));
        };
        let op = pd.crew.0.get(&opid).unwrap();

        let inputs = industry.input(op.rank);
        let outputs = industry.output(op.rank);
        Ok((inputs, outputs))
    }
}

#![allow(unexpected_cfgs)]
use std::collections::BTreeMap;
use std::sync::Arc;

use rand::rngs::ThreadRng;
use rand::RngExt;

pub mod planet;
pub mod scan;
pub mod station;

use scan::ScanResult;
use station::StationId;

use crate::galaxy::station::Station;

pub type SpaceUnit = u32;
pub type SpaceCoord = (SpaceUnit, SpaceUnit, SpaceUnit);
type GalaxySector = (
    (SpaceUnit, SpaceUnit),
    (SpaceUnit, SpaceUnit),
    (SpaceUnit, SpaceUnit),
);

const SECTOR_SIZE: (SpaceUnit, SpaceUnit, SpaceUnit) = (5000, 5000, 5000);
const PLANETS_PER_SECTOR: usize = 3;
const STATION_FPLANET_DIST: f64 = 500.0;

#[allow(dead_code)]
#[derive(Debug)]
pub enum SpaceObject {
    BaseStation(StationId, Arc<station::Station>),
    Planet(Arc<planet::Planet>),
}

pub struct Galaxy {
    objects: BTreeMap<SpaceCoord, SpaceObject>,
    discovered: Vec<GalaxySector>,
}

impl Galaxy {
    pub fn init() -> Galaxy {
        Galaxy {
            objects: BTreeMap::new(),
            discovered: vec![],
        }
    }

    // X, Y and Z can be any point from the given sector
    // Returns the index in the "discovered" vector
    pub fn generate_sector(&mut self, coord: &SpaceCoord) -> usize {
        let (x, y, z) = coord;
        let (secx, secy, secz) = compute_sector(*x, *y, *z);
        log::debug!(
            "Generating sector ({}-{}, {}-{}, {}-{})",
            secx.0,
            secx.1,
            secy.0,
            secy.1,
            secz.0,
            secz.1,
        );
        let ind = self.discovered.len();
        self.discovered.push((secx, secy, secz));
        let mut rng = rand::rng();
        for _ in 0..PLANETS_PER_SECTOR {
            let x = rng.random_range(secx.0..secx.1);
            let y = rng.random_range(secy.0..secy.1);
            let z = rng.random_range(secz.0..secz.1);
            let planet = planet::Planet::random((x, y, z), &mut rng);
            if self
                .insert(&(x, y, z), SpaceObject::Planet(Arc::new(planet)))
                .is_none()
            {
                continue;
            }
        }
        ind
    }

    pub fn is_discovered(&self, coord: &SpaceCoord) -> bool {
        let (x, y, z) = coord;
        for ((sx, ex), (sy, ey), (sz, ez)) in self.discovered.iter() {
            if (x < sx) || (x > ex) || (y < sy) || (y > ey) || (z < sz) || (z > ez) {
                continue;
            }
            return true;
        }
        false
    }

    pub fn get<'a>(&'a self, coord: &SpaceCoord) -> Option<&'a SpaceObject> {
        self.objects.get(coord)
    }

    pub fn insert(&mut self, coord: &SpaceCoord, obj: SpaceObject) -> Option<()> {
        if self.objects.contains_key(coord) {
            return None;
        }
        self.objects.insert(*coord, obj);
        Some(())
    }

    fn list_objects_in_sector(&self, sector: &GalaxySector) -> Vec<&SpaceObject> {
        let mut objects = vec![];
        for (coord, obj) in self.objects.iter() {
            let (x, y, z) = coord;
            if (x < &sector.0 .0) || (x > &sector.0 .1) {
                continue;
            }
            if (y < &sector.1 .0) || (y > &sector.1 .1) {
                continue;
            }
            if (z < &sector.2 .0) || (z > &sector.2 .1) {
                continue;
            }
            objects.push(obj);
        }
        objects
    }

    pub async fn get_station(&self, coord: &SpaceCoord) -> Option<Arc<station::Station>> {
        let obj = self.get(coord)?;
        let SpaceObject::BaseStation(_, station) = obj else {
            return None;
        };
        Some(station.clone())
    }

    pub async fn get_planet(&self, coord: &SpaceCoord) -> Option<Arc<planet::Planet>> {
        let obj = self.get(coord)?;
        let SpaceObject::Planet(planet) = obj else {
            return None;
        };
        Some(planet.clone())
    }

    pub async fn init_new_station(&mut self) -> (StationId, Arc<Station>) {
        let mut rng = rand::rng();

        let mut seccoord = (rng.random(), rng.random(), rng.random());
        while self.is_discovered(&seccoord) {
            seccoord = (rng.random(), rng.random(), rng.random());
        }
        let id = rng.random();
        let ind = self.generate_sector(&seccoord);
        let sector = self.discovered.get(ind).unwrap();

        let Some(SpaceObject::Planet(pla)) = self
            .list_objects_in_sector(sector)
            .iter()
            .filter(|obj| matches!(obj, SpaceObject::Planet(_)))
            .nth(0)
        else {
            unreachable!("Planet inside generated sector");
        };

        let mut coord;
        let mut retry_n = 0;
        loop {
            coord = get_rand_coord_near(&pla.position, STATION_FPLANET_DIST, &mut rng);
            while !is_in_sector(&coord, sector) || self.get(&coord).is_some() {
                coord = get_rand_coord_near(&pla.position, STATION_FPLANET_DIST, &mut rng);
            }

            let mut mindist = None;
            for pla in self
                .list_objects_in_sector(sector)
                .iter()
                .filter_map(|obj| {
                    if let SpaceObject::Planet(p) = obj {
                        Some(p)
                    } else {
                        None
                    }
                })
            {
                let dist = get_distance(&pla.position, &coord);
                if let Some(ref mut m) = mindist {
                    if dist < *m {
                        *m = dist;
                    }
                } else {
                    mindist = Some(dist);
                }
            }

            let mindist = mindist.unwrap();
            if (mindist - STATION_FPLANET_DIST).abs() < 1.0 {
                break;
            }
            retry_n += 1;
            log::warn!("{retry_n} {mindist} {STATION_FPLANET_DIST}");
            if retry_n > 10000 {
                panic!("Too many retries");
            }
        }
        let station = Arc::new(station::Station::init(id, coord));
        self.insert(&coord, SpaceObject::BaseStation(id, station.clone()))
            .unwrap();
        (id, station)
    }

    pub async fn scan_sector(&self, rank: u8, center: &SpaceCoord) -> ScanResult {
        let strengh = (rank - 1) as f64;
        let mut results = ScanResult::empty();
        debug_assert!(strengh >= 0.0);
        for sector in sectors_around(center, strengh) {
            for obj in self.list_objects_in_sector(&sector) {
                results.add(rank, obj).await;
            }
        }
        debug_assert!(!results.planets.is_empty()); // We should always have some planets
        results
    }
}

#[inline]
pub fn get_delta(a: &SpaceCoord, b: &SpaceCoord) -> (f64, f64, f64) {
    (
        (b.0 as f64) - (a.0 as f64),
        (b.1 as f64) - (a.1 as f64),
        (b.2 as f64) - (a.2 as f64),
    )
}

#[inline]
pub fn get_distance(a: &SpaceCoord, b: &SpaceCoord) -> f64 {
    let delta = get_delta(a, b);
    (delta.0.powf(2.0) + delta.1.powf(2.0) + delta.2.powf(2.0)).sqrt()
}

#[inline]
pub fn get_direction(a: &SpaceCoord, b: &SpaceCoord) -> (f64, f64, f64) {
    let delta = get_delta(a, b);
    let distance = get_distance(a, b);
    (delta.0 / distance, delta.1 / distance, delta.2 / distance)
}

fn compute_sector(x: SpaceUnit, y: SpaceUnit, z: SpaceUnit) -> GalaxySector {
    let start_x = x - (x % SECTOR_SIZE.0);
    let end_x = start_x.saturating_add(SECTOR_SIZE.0);
    let start_y = y - (y % SECTOR_SIZE.1);
    let end_y = start_y.saturating_add(SECTOR_SIZE.1);
    let start_z = z - (z % SECTOR_SIZE.2);
    let end_z = start_z.saturating_add(SECTOR_SIZE.2);
    ((start_x, end_x), (start_y, end_y), (start_z, end_z))
}

pub fn translation(start: SpaceCoord, direction: (f64, f64, f64), dist: f64) -> SpaceCoord {
    (
        ((start.0 as f64) + (dist * direction.0)) as SpaceUnit,
        ((start.1 as f64) + (dist * direction.1)) as SpaceUnit,
        ((start.2 as f64) + (dist * direction.2)) as SpaceUnit,
    )
}

fn is_in_sector(coord: &SpaceCoord, sector: &GalaxySector) -> bool {
    coord.0 >= sector.0 .0
        && coord.0 < sector.0 .1
        && coord.1 >= sector.1 .0
        && coord.1 < sector.1 .1
        && coord.2 >= sector.2 .0
        && coord.2 < sector.2 .1
}

fn sectors_around(center: &SpaceCoord, radius: f64) -> Vec<GalaxySector> {
    let mut sectors = vec![];
    let centersec = compute_sector(center.0, center.1, center.2);

    let xsecstart = ((centersec.0 .0 as f64) - (radius * (SECTOR_SIZE.0 as f64))) as SpaceUnit;
    let nsector_x = (1.0 + (2.0 * radius * (SECTOR_SIZE.0 as f64))) as SpaceUnit;
    let xsecend = ((centersec.0 .1 as f64) + (radius * (SECTOR_SIZE.0 as f64))) as SpaceUnit;
    debug_assert_eq!(xsecstart + (nsector_x * SECTOR_SIZE.0), xsecend);

    let ysecstart = ((centersec.1 .0 as f64) - (radius * (SECTOR_SIZE.1 as f64))) as SpaceUnit;
    let nsector_y = (1.0 + (2.0 * radius * (SECTOR_SIZE.1 as f64))) as SpaceUnit;
    let ysecend = ((centersec.1 .1 as f64) + (radius * (SECTOR_SIZE.1 as f64))) as SpaceUnit;
    debug_assert_eq!(ysecstart + (nsector_y * SECTOR_SIZE.1), ysecend);

    let zsecstart = ((centersec.2 .0 as f64) - (radius * (SECTOR_SIZE.2 as f64))) as SpaceUnit;
    let nsector_z = (1.0 + (2.0 * radius * (SECTOR_SIZE.2 as f64))) as SpaceUnit;
    let zsecend = ((centersec.2 .1 as f64) + (radius * (SECTOR_SIZE.2 as f64))) as SpaceUnit;
    debug_assert_eq!(zsecstart + (nsector_z * SECTOR_SIZE.2), zsecend);

    for sx in 0..nsector_x {
        for sy in 0..nsector_y {
            for sz in 0..nsector_z {
                sectors.push((
                    (
                        xsecstart + (sx * SECTOR_SIZE.0),
                        xsecstart + ((sx + 1) * SECTOR_SIZE.0),
                    ),
                    (
                        ysecstart + (sy * SECTOR_SIZE.1),
                        ysecstart + ((sy + 1) * SECTOR_SIZE.1),
                    ),
                    (
                        zsecstart + (sz * SECTOR_SIZE.2),
                        zsecstart + ((sz + 1) * SECTOR_SIZE.2),
                    ),
                ))
            }
        }
    }

    sectors
}

fn get_rand_coord_near(obj: &SpaceCoord, dist: f64, rng: &mut ThreadRng) -> SpaceCoord {
    let theta = rng.random_range(0.0..2.0 * std::f64::consts::PI); // azimuthal angle
    let phi = rng.random_range(0.0..std::f64::consts::PI); // polar angle
    let x = (obj.0 as f64) + (dist * phi.sin() * theta.cos());
    let y = (obj.1 as f64) + (dist * phi.sin() * theta.sin());
    let z = (obj.2 as f64) + (dist * phi.cos());
    (x as u32, y as u32, z as u32)
}

#[test]
fn test_compute_sector() {
    let mut rng: rand::rngs::SmallRng = rand::make_rng();
    for _ in 0..10000000 {
        let x = rng.random();
        let y = rng.random();
        let z = rng.random();
        let sec = compute_sector(x, y, z);
        assert!(is_in_sector(&(x, y, z), &sec));
    }
    assert_eq!(
        compute_sector(SECTOR_SIZE.0 - 1, 0, 0),
        ((0, SECTOR_SIZE.0), (0, SECTOR_SIZE.1), (0, SECTOR_SIZE.2))
    );
    assert_eq!(
        compute_sector(0, SECTOR_SIZE.1 - 1, 0),
        ((0, SECTOR_SIZE.0), (0, SECTOR_SIZE.1), (0, SECTOR_SIZE.2))
    );
    assert_eq!(
        compute_sector(0, 0, SECTOR_SIZE.2 - 1),
        ((0, SECTOR_SIZE.0), (0, SECTOR_SIZE.1), (0, SECTOR_SIZE.2))
    );

    assert_eq!(
        compute_sector(SECTOR_SIZE.0, 0, 0),
        (
            (SECTOR_SIZE.0, 2 * SECTOR_SIZE.0),
            (0, SECTOR_SIZE.1),
            (0, SECTOR_SIZE.2)
        )
    );
    assert_eq!(
        compute_sector(0, SECTOR_SIZE.1, 0),
        (
            (0, SECTOR_SIZE.0),
            (SECTOR_SIZE.1, 2 * SECTOR_SIZE.1),
            (0, SECTOR_SIZE.2)
        )
    );
    assert_eq!(
        compute_sector(0, 0, SECTOR_SIZE.2),
        (
            (0, SECTOR_SIZE.0),
            (0, SECTOR_SIZE.1),
            (SECTOR_SIZE.2, 2 * SECTOR_SIZE.2)
        )
    );
}

// Mutex acquisition order
// - Taken names
// - Player index
// - Player list
// - Player
// - Station
// - Galaxy
// - Market
// - SyslogFifo
// - PlayerFifo

use std::sync::Arc;
use std::time::{Duration, Instant};

use mea::mpsc::{BoundedReceiver, BoundedSender, RecvError};
use mea::rwlock::RwLock;

#[cfg(not(feature = "testing"))]
use mea::mpsc::TryRecvError;

use base64::{prelude::BASE64_STANDARD, Engine};
use rand::{Rng, RngExt};

use crate::errors::Errcode;
use crate::galaxy::scan::ScanResult;
use crate::galaxy::station::{Station, StationId};
use crate::galaxy::Galaxy;
use crate::market::{Market, MarketTx, MARKET_CHANGE_SEC};
use crate::player::{Player, PlayerId, PlayerKey};
use crate::ship::resources::{ExtractionInfo, Resource};
use crate::ship::{Ship, ShipId, ShipState};
use crate::syslog::{SyslogEvent, SyslogFifo, SyslogRecv, SyslogSend};
use crate::utils::{BoxFuture, ShardedLockedData};

#[cfg(not(feature = "extraspeed"))]
const ITER_PERIOD: Duration = Duration::from_millis(20);

#[cfg(feature = "extraspeed")]
const ITER_PERIOD: Duration = Duration::from_micros(20);

//     Equipment becomes more and more expansive

pub enum GameSignal {
    Stop,
    Tick,
}

#[derive(Clone)]
pub struct Game {
    // Locked
    pub players: Arc<ShardedLockedData<PlayerId, Arc<RwLock<Player>>>>,
    pub player_index: Arc<ShardedLockedData<PlayerKey, PlayerId>>,
    pub taken_names: Arc<ShardedLockedData<String, PlayerId>>,
    pub galaxy: Arc<RwLock<Galaxy>>,

    pub init_station: (StationId, Arc<Station>),
    pub market: Arc<Market>,
    pub syslog: SyslogSend,
    pub fifo_events: SyslogFifo,
    pub tstart: f64,
    pub send_sig: BoundedSender<GameSignal>,
}

impl Game {
    pub async fn init<F>(handle_thread: F) -> (std::thread::JoinHandle<()>, Game)
    where
        F: FnOnce(BoundedReceiver<GameSignal>, SyslogRecv, Game) -> std::thread::JoinHandle<()>,
    {
        let (send_stop, recv_stop) = mea::mpsc::bounded(5);
        let (syssend, sysrecv) = SyslogSend::channel();
        let tstart = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .unwrap()
            .as_secs_f64();
        let mut galaxy = Galaxy::init();
        let init_station = galaxy.init_new_station().await;
        let data = Game {
            send_sig: send_stop,
            galaxy: Arc::new(RwLock::new(galaxy)),
            market: Arc::new(Market::init()),
            taken_names: Arc::new(ShardedLockedData::new(100)),
            players: Arc::new(ShardedLockedData::new(100)),
            player_index: Arc::new(ShardedLockedData::new(100)),
            syslog: syssend.clone(),
            fifo_events: sysrecv.fifo.clone(),
            tstart,
            init_station,
        };

        let thread_data = data.clone();
        let thread = handle_thread(recv_stop, sysrecv, thread_data);
        (thread, data)
    }

    #[allow(unused_variables, unused_mut)]
    pub async fn start(&self, mut stop: BoundedReceiver<GameSignal>, syslog: SyslogRecv) {
        log::info!("Game thread started");
        let sleepmin_iter = ITER_PERIOD;
        let mut last_iter = Instant::now();
        let mut market_last_tick = Instant::now();
        let mut rng: rand::rngs::SmallRng = rand::make_rng();

        'main: loop {
            #[cfg(feature = "testing")]
            let got = stop.recv().await;

            #[cfg(not(feature = "testing"))]
            let got = match stop.try_recv() {
                Ok(res) => Ok(res),
                Err(TryRecvError::Empty) => Ok(GameSignal::Tick),
                Err(TryRecvError::Disconnected) => {
                    log::error!("Can't get next tick / stop signal: disconnected");
                    Err(RecvError::Disconnected)
                }
            };

            match got {
                Ok(GameSignal::Tick) => {
                    self.threadloop(&mut rng, &mut market_last_tick, &syslog)
                        .await;

                    #[cfg(not(feature = "testing"))]
                    {
                        let took = Instant::now() - last_iter;
                        let t = sleepmin_iter.saturating_sub(took);
                        crate::utils::sleep(t).await;
                        last_iter = Instant::now();
                    }
                }

                Ok(GameSignal::Stop) => break 'main,
                Err(RecvError::Disconnected) => {
                    log::error!("Got disconnected channel in game thread");
                    break 'main;
                }
            }
        }
        log::info!("Exiting game thread");
    }

    async fn threadloop<R: Rng>(&self, rng: &mut R, mlt: &mut Instant, syslog: &SyslogRecv) {
        let market_change_proba = (mlt.elapsed().as_secs_f64() / MARKET_CHANGE_SEC).min(1.0);

        let all_players: Vec<PlayerId> = self.players.get_all_keys().await;
        for player_id in all_players {
            let player = self.players.clone_val(&player_id).await.unwrap();
            let mut player = player.write().await;
            player.update_money(syslog, ITER_PERIOD.as_secs_f64()).await;

            for (_, station) in player.stations.iter() {
                station
                    .update_crafting(ITER_PERIOD.as_secs_f64(), &player_id)
                    .await;
            }

            let mut deadship = vec![];
            for (id, ship) in player.ships.iter_mut() {
                match ship.state {
                    ShipState::InFlight(..) => {
                        let finished = ship.update_flight(ITER_PERIOD.as_secs_f64());
                        if finished {
                            ship.state = ShipState::Idle;
                            if ship.hull_decay >= ship.hull_resistance {
                                deadship.push(*id);
                            } else {
                                syslog
                                    .event(player_id, SyslogEvent::ShipFlightFinished(*id))
                                    .await;
                            }
                        }
                    }

                    ShipState::Extracting(..) => {
                        let finished = ship.update_extract(ITER_PERIOD.as_secs_f64());
                        if finished {
                            ship.state = ShipState::Idle;
                            syslog
                                .event(player_id, SyslogEvent::ExtractionStopped(*id))
                                .await;
                        }
                    }
                    _ => {}
                }
            }
            for id in deadship {
                syslog
                    .event(player_id, SyslogEvent::ShipDestroyed(id))
                    .await;
                player.ships.remove(&id);
            }
        }

        if rng.random_bool(market_change_proba) {
            #[cfg(not(feature = "testing"))]
            self.market.update_prices(rng).await;
            *mlt = Instant::now();
        }

        syslog.update().await;
    }

    pub async fn new_player(&self, name: String) -> Result<(PlayerId, String), Errcode> {
        if self.taken_names.contains_key(&name).await {
            return Err(Errcode::PlayerAlreadyExists(name));
        }

        let player = Player::new(self.init_station.clone(), name.clone());
        let pid = player.id;
        self.taken_names.insert(name.clone(), pid).await;

        let key = BASE64_STANDARD.encode(player.key);

        self.player_index.insert(player.key, player.id).await;
        self.players
            .insert(player.id, Arc::new(RwLock::new(player)))
            .await;
        self.syslog.event(&pid, SyslogEvent::GameStarted).await;
        Ok((pid, key))
    }

    pub async fn get_player(
        &self,
        key: &PlayerKey,
    ) -> Result<(PlayerId, Arc<RwLock<Player>>), Errcode> {
        let Some(id) = self.player_index.clone_val(key).await else {
            return Err(Errcode::NoPlayerWithKey);
        };
        let player = self.players.clone_val(&id).await.unwrap();
        if player.read().await.lost {
            return Err(Errcode::PlayerLost);
        }
        Ok((id, player.clone()))
    }

    pub async fn get_syslogs(&self, pkey: &PlayerKey) -> Result<Vec<(f64, SyslogEvent)>, Errcode> {
        let (pid, _) = self.get_player(pkey).await?;
        let allfifo = self.fifo_events.read().await;
        let Some(fifo) = allfifo.clone_val(&pid).await else {
            return Ok(vec![]);
        };
        let mut fifo = fifo.write().await;
        Ok(fifo.remove_all())
    }

    pub async fn map_station<F, T>(
        &self,
        pkey: &PlayerKey,
        id: &StationId,
        f: F,
    ) -> Result<T, Errcode>
    where
        F: for<'a> FnOnce(&'a PlayerId, &'a Station) -> BoxFuture<'a, Result<T, Errcode>>,
    {
        let (pid, player) = self.get_player(pkey).await?;
        let player = player.read().await;
        let Some(station) = player.stations.get(id) else {
            return Err(Errcode::NoSuchStation(*id));
        };
        let data = f(&pid, station).await;
        data
    }

    pub async fn map_ship<F, T>(&self, pkey: &PlayerKey, id: &ShipId, f: F) -> Result<T, Errcode>
    where
        F: for<'a> FnOnce(PlayerId, &'a Ship) -> BoxFuture<'a, Result<T, Errcode>>,
    {
        let (pid, player) = self.get_player(pkey).await?;
        let player = player.read().await;
        let ship = player.get_ship(id)?;
        let data = f(pid, ship).await;
        data
    }

