use serde::{Deserialize, Serialize};
use std::collections::BTreeMap;
use strum::IntoEnumIterator;

use crate::{crew::CrewMember, ship::resources::Resource};

const MAX_AVG_AMPL: f64 = 5.5 / 100.0;
const STD_DIV: f64 = 1.15;
pub const MARKET_CHANGE_SEC: f64 = 20.0;
pub const BASE_FEE_RATE: f64 = 25.0 / 100.0;
const FEE_RATE_DEC_POWF: f64 = 1.15;
const UPD_PRICE_PROBA: f64 = 0.80;

// Buying 500000 worth of a resource will increase the price between 10% and 30%
// After  500000 credits, will be capped at btwn 10 and 30%
const PRICE_INC_CAP: f64 = 500_000.0;
const PRICE_INC_RANGE_MAX: f64 = 70.0 / 100.0;
const PRICE_INC_RANGE_MIN: f64 = 30.0 / 100.0;

#[inline]
pub fn fee_rate(rank: u8) -> f64 {
    BASE_FEE_RATE / (rank as f64).powf(FEE_RATE_DEC_POWF)
}

pub struct Market {
    pub prices: BTreeMap<Resource, RwLock<f64>>,
}

impl Market {
    pub fn init() -> Market {
        let mut prices = BTreeMap::new();
        for r in Resource::iter() {
            prices.insert(r, RwLock::new(r.base_price()));
        }
        Market { prices }
    }

    pub async fn to_json(&self) -> serde_json::Value {
        let mut resources = BTreeMap::new();
        for (res, price) in self.prices.iter() {
            let price = price.read().await;
            resources.insert(res, *price);
        }
        serde_json::to_value(resources).unwrap()
    }

    fn rand_distrib(&self, r: &Resource, now_price: f64) -> Normal<f64> {
        let base_price = r.base_price();
        let pratio = now_price / base_price;
        // 0.3    AVG = 1 - 0.3 = 0.7  * MAX AMPL = 3.5 * 0.7  =  2.45
        // 1.3    AVG = 1 - 1.3 = -0.3 * MAX AMPL = 3.5 * -0.3 = -1.05
        let avg = (1.0 - pratio) * MAX_AVG_AMPL;
        let std = avg.abs() + (MAX_AVG_AMPL / STD_DIV);

        rand_distr::Normal::new(avg, std).unwrap()
    }

    fn get_new_price<R: Rng>(&self, rng: &mut R, r: &Resource, old: f64) -> f64 {
        let distr = self.rand_distrib(r, old);
        let change = distr.sample(rng);
        old * (1.0 + change)
    }

    pub async fn update_prices<R: Rng>(&self, rng: &mut R) {
        for (res, price) in self.prices.iter() {
            if !rng.random_bool(UPD_PRICE_PROBA) {
                continue;
            }
            let mut price = price.write().await;

            let new_price = self.get_new_price(rng, res, *price);
            log::trace!(
                "{res:?} {new_price} ({:?}%)",
                (new_price / res.base_price()) * 100.0
            );
            *price = new_price;
        }
    }

    pub async fn buy(&self, trader: &CrewMember, r: &Resource, amnt: f64) -> MarketTx {
        assert!(amnt > 0.0);
        let fee_rate = fee_rate(trader.rank);

        let price = self.prices.get(r).unwrap();
        let price = price.read().await;
        assert!(*price > 0.0);
        let cost = amnt * *price;
        let fees = cost * fee_rate;

        // let price_inc_max = (cost / PRICE_INC_CAP).max(1.0) * PRICE_INC_RANGE_MAX;
        // let price_inc_min = (cost / PRICE_INC_CAP).max(1.0) * PRICE_INC_RANGE_MIN;
        // let mut rng = rand::rng();
        // let inc = rng.random_range(price_inc_min..=price_inc_max);
        // *self.prices.get_mut(r).unwrap() *= 1.0 + inc;

        MarketTx {
            added_cargo: Some((*r, amnt)),
            removed_money: Some(cost + fees),
            fees,
            ..Default::default()
        }
    }

    pub async fn sell(&self, trader: &CrewMember, r: &Resource, amnt: f64) -> MarketTx {
        assert!(amnt > 0.0);
        let fee_rate = fee_rate(trader.rank);

        let price = self.prices.get(r).unwrap();
        let price = price.read().await;
        assert!(*price > 0.0);
        let cost = amnt * *price;
        let fees = cost * fee_rate;

        // let price_dec_max = (cost / PRICE_INC_CAP).max(1.0) * PRICE_INC_RANGE_MAX;
        // let price_dec_min = (cost / PRICE_INC_CAP).max(1.0) * PRICE_INC_RANGE_MIN;
        // let mut rng = rand::rng();
        // let dec = rng.random_range(price_dec_min..=price_dec_max);
        // *self.prices.get_mut(r).unwrap() *= 1.0 - dec;

        MarketTx {
            removed_cargo: Some((*r, amnt)),
            added_money: Some(cost - fees),
            fees,
            ..Default::default()
        }
    }
}

#[derive(Serialize, Deserialize, Default, Debug)]
pub struct MarketTx {
    pub added_cargo: Option<(Resource, f64)>,
    pub removed_cargo: Option<(Resource, f64)>,

    pub added_money: Option<f64>,
    pub removed_money: Option<f64>,
    pub fees: f64,
}

use std::collections::hash_map::DefaultHasher;
use std::collections::BTreeMap;
use std::hash::Hasher;
use std::sync::Arc;
use std::time::Instant;

use rand::Rng;

use crate::crew::CrewId;
use crate::errors::Errcode;
use crate::galaxy::station::{Station, StationId};
use crate::ship::cargo::ShipCargo;
use crate::ship::module::{ShipModuleId, ShipModuleType};
use crate::ship::upgrade::ShipUpgrade;
use crate::ship::{Ship, ShipId};
use crate::syslog::{SyslogEvent, SyslogRecv};

const INIT_MONEY: f64 = 72000.0;

pub type PlayerId = u64;
pub type PlayerKey = [u8; 128];

// Game state for a single player
pub struct Player {
    pub created: Instant,
    pub id: PlayerId,
    pub key: PlayerKey,
    pub score: f64,
    pub lost: bool,

    pub name: String,
    pub money: f64,
    pub costs: f64,

    pub stations: BTreeMap<StationId, Arc<Station>>,
    pub ships: BTreeMap<ShipId, Ship>,
}

impl Player {
    pub fn new(initstation: (StationId, Arc<Station>), name: String) -> Player {
        let mut hasher = DefaultHasher::new();
        hasher.write(name.as_bytes());
        let mut rng = rand::rng();
        let mut randbytes = [0; 128];
        rng.fill_bytes(&mut randbytes);

        #[allow(unused_mut)]
        let mut money = INIT_MONEY;

        #[cfg(feature = "testing")]
        if name.starts_with("test-rich") {
            money *= 10000.0;
        }
        let mut stations = BTreeMap::new();
        stations.insert(initstation.0, initstation.1);
        Player {
            created: Instant::now(),
            key: randbytes,
            id: hasher.finish(),
            lost: false,

            money,
            score: 0.0,
            costs: 0.0,

            name,
            stations,
            ships: BTreeMap::new(),
        }
    }

    pub fn get_ship<'a>(&'a self, id: &ShipId) -> Result<&'a Ship, Errcode> {
        self.ships.get(id).ok_or(Errcode::ShipNotFound(*id))
    }

    pub fn get_ship_mut<'a>(&'a mut self, id: &ShipId) -> Result<&'a mut Ship, Errcode> {
        self.ships.get_mut(id).ok_or(Errcode::ShipNotFound(*id))
    }

    #[inline]
    pub fn ship_in_station(&self, ship: &ShipId, station: &StationId) -> Result<bool, Errcode> {
        let ship = self.get_ship(ship)?;
        let Some(station) = self.stations.get(station) else {
            return Err(Errcode::NoSuchStation(*station));
        };
        Ok(ship.position == station.position)
    }

    //// Interfaces for game

    pub async fn update_costs(&mut self) {
        self.costs = 0.0;

        for station in self.stations.values() {
            // Deadlock because of this
            self.costs += station.sum_all_wages(&self.id).await;
        }
        self.costs += self
            .ships
            .values()
            .map(|ship| ship.crew.sum_wages())
            .sum::<f64>();
    }

    pub async fn update_money(&mut self, syslog: &SyslogRecv, tdelta: f64) {
        let before = self.money < (self.costs * 60.0);
        self.money -= self.costs * tdelta;
        let after = self.money < (self.costs * 60.0);
        if after && !before {
            let tleft = std::time::Duration::from_secs_f64(self.money / self.costs);
            syslog.event(self.id, SyslogEvent::LowFunds(tleft)).await;
        }
        if self.money < 0.0 && !self.lost {
            self.lost = true;
            syslog.event(self.id, SyslogEvent::GameLost).await;
        }
    }

    pub async fn buy_ship(
        &mut self,
        station_id: &StationId,
        ship_id: &ShipId,
    ) -> Result<ShipId, Errcode> {
        let Some(station) = self.stations.get(station_id) else {
            return Err(Errcode::NoSuchStation(*station_id));
        };

        let ship_opt = {
            let mut data = None;
            let shipyard = station.shipyard.read().await;
            for (n, ship) in shipyard.iter().enumerate() {
                if &ship.id == ship_id {
                    data = Some((n, ship.compute_price()));
                }
            }
            data
        };

        let Some((index, price)) = ship_opt else {
            return Err(Errcode::ShipNotFound(*ship_id));
        };

        if price > self.money {
            return Err(Errcode::NotEnoughMoney(self.money, price));
        }

        let mut ship = station.buy_ship(index).await;
        let ship_id = ship.id;
        ship.owner = self.id;
        self.money -= price;
        self.ships.insert(ship_id, ship);
        Ok(ship_id)
    }

    pub async fn buy_ship_module(
        &mut self,
        station_id: &StationId,
        ship_id: &ShipId,
        modtype: ShipModuleType,
    ) -> Result<ShipModuleId, Errcode> {
        if !self.ship_in_station(ship_id, station_id)? {
            return Err(Errcode::ShipNotInStation);
        }
        let ship = self.ships.get_mut(ship_id).unwrap();

        let price = modtype.get_price_buy();
        if self.money < price {
            return Err(Errcode::NotEnoughMoney(self.money, price));
        }
        self.money -= price;
        let id = (ship.modules.len() + 1) as ShipModuleId;
        ship.modules.insert(id, modtype.new_module());
        Ok(id)
    }

    pub async fn buy_ship_upgrade(
        &mut self,
        station: &StationId,
        ship_id: &ShipId,
        upgrade: &ShipUpgrade,
    ) -> Result<f64, Errcode> {
        let ship = self
            .ships
            .get_mut(ship_id)
            .ok_or(Errcode::ShipNotFound(*ship_id))?;
        let Some(station) = self.stations.get(station).cloned() else {
            return Err(Errcode::NoSuchStation(*station));
        };

        let price = station.get_ship_upgrade_price(ship, upgrade);
        if price > self.money {
            return Err(Errcode::NotEnoughMoney(self.money, price));
        }

        self.money -= price;
        upgrade.install(ship);
        Ok(price)
    }

    pub async fn buy_ship_module_upgrade(
        &mut self,
        station_id: &StationId,
        ship_id: &ShipId,
        mod_id: &ShipModuleId,
    ) -> Result<(f64, u8), Errcode> {
        if !self.ship_in_station(ship_id, station_id)? {
            return Err(Errcode::ShipNotInStation);
        }
        // SAFETY Checked on the function above
        let ship = self.ships.get_mut(ship_id).unwrap();
        let Some(ref mut module) = ship.modules.get_mut(mod_id) else {
            return Err(Errcode::NoSuchModule(*mod_id));
        };
        let price = module.price_next_rank();
        if price > self.money {
            return Err(Errcode::NotEnoughMoney(self.money, price));
        }

        self.money -= price;
        module.rank += 1;

        Ok((price, module.rank))
    }

    pub async fn upgrade_ship_crew(
        &mut self,
        station_id: &StationId,
        ship_id: &ShipId,
        crew_id: &CrewId,
    ) -> Result<(f64, u8), Errcode> {
        if !self.ship_in_station(ship_id, station_id)? {
            return Err(Errcode::ShipNotInStation);
        };
        // SAFETY Checked in function above
        let ship = self.ships.get_mut(ship_id).unwrap();
        let res = {
            let Some(ref mut cm) = ship.crew.0.get_mut(crew_id) else {
                return Err(Errcode::CrewMemberNotFound(*crew_id));
            };

            let price = cm.price_next_rank();
            if price > self.money {
                return Err(Errcode::NotEnoughMoney(self.money, price));
            }

            self.money -= price;
            cm.rank += 1;
            (price, cm.rank)
        };
        ship.update_perf_stats();
        Ok(res)
    }

    pub async fn upgrade_station_crew(
        &mut self,
        station_id: &StationId,
        crew_id: &CrewId,
    ) -> Result<(f64, u8), Errcode> {
        let Some(station) = self.stations.get(station_id) else {
            return Err(Errcode::NoSuchStation(*station_id));
        };
        let res = station
            .upgrade_station_crew(&self.id, &mut self.money, crew_id)
            .await;
        match res {
            Ok(v) => {
                self.update_costs().await;
                Ok(v)
            }
            Err(e) => Err(e),
        }
    }

    pub async fn buy_station_cargo(
        &mut self,
        station_id: &StationId,
        amnt: usize,
    ) -> Result<ShipCargo, Errcode> {
        let Some(station) = self.stations.get_mut(station_id) else {
            return Err(Errcode::NoSuchStation(*station_id));
        };
        let cost = (amnt as f64) * station.cargo_price(&self.id).await;
        if cost > self.money {
            return Err(Errcode::NotEnoughMoney(self.money, cost));
        }
        self.money -= cost;
        Ok(station.add_cargo_cap(&self.id, amnt).await)
    }
}

use std::collections::BTreeMap;

use serde::{Deserialize, Serialize};

use super::resources::Resource;

#[derive(Clone, Debug, Default, Serialize, Deserialize)]
pub struct ShipCargo {
    pub capacity: f64,
    pub usage: f64,
    pub resources: BTreeMap<Resource, f64>,
}

impl ShipCargo {
    pub const fn with_capacity(cap: f64) -> ShipCargo {
        ShipCargo {
            usage: 0.0,
            capacity: cap,
            resources: BTreeMap::new(),
        }
    }

    pub fn slowing_ratio(&self) -> f64 {
        // let usage_ratio = self.usage / self.capacity;
        0.0
    }

    pub fn add_resource(&mut self, res: &Resource, mut amnt: f64) -> f64 {
        let added = res.volume() * amnt;
        if self.usage == self.capacity {
            return 0.0;
        } else if (self.usage + added) > self.capacity {
            let overflow = (self.usage + added) - self.capacity;
            amnt -= overflow / res.volume();
            self.usage = self.capacity;
        } else {
            self.usage += added;
        }

        if let Some(stock) = self.resources.get_mut(res) {
            *stock += amnt;
        } else {
            self.resources.insert(*res, amnt);
        }
        amnt
    }

    pub fn is_full(&self) -> bool {
        self.usage == self.capacity
    }

    pub fn unload(&mut self, resource: &Resource, amnt: f64) -> f64 {
        if let Some(got) = self.resources.get_mut(resource) {
            let unload = got.min(amnt);
            *got -= unload;
            self.usage = (self.usage - (resource.volume() * unload)).max(0.0);
            self.usage = (self.usage * 1000.0).round() / 1000.0;
            unload
        } else {
            0.0
        }
    }

    // Compute how much of a resource we can store (based on its volume)
    pub fn space_for(&self, resource: &Resource) -> f64 {
        let capleft = self.capacity - self.usage;
        capleft / resource.volume()
    }
}

#[test]
fn test_cargo_overflow() {
    let mut cargo = ShipCargo::with_capacity(100.0 * Resource::Carbon.volume());
    let added = cargo.add_resource(&Resource::Carbon, 95.0);
    assert_eq!(added, 95.0);

    let added = cargo.add_resource(&Resource::Carbon, 10.0);
    assert_eq!(added, 5.0);
    assert_eq!(cargo.usage, cargo.capacity);
}

