    #[serde(default)]
    pub fuel_tank: f64,
    #[serde(default)]
    pub hull_decay: f64,
    #[serde(default)]
    pub pilot: Option<CrewId>,
    #[serde(default)]
    pub state: ShipState,
    #[serde(default)]
    pub stats: shipstats::ShipStats,
}

impl Ship {
    pub fn init_shipyard(position: SpaceCoord) -> Vec<Ship> {
        let mut rng = rand::rng();
        vec![
            Ship::light(rng.random(), position),
            Ship::medium(rng.random(), position),
