    let data = srv
        .map_ship(&pkey, &ship_id, |_, ship| {
            Box::pin(async move {
                let cost = ship.compute_travel_costs((x, y, z))?;
                Ok(to_value(cost).unwrap())
            })
        })
        .await;
    build_response(data)
